external_knowledge:
- A 'successful connection' refers to a contact attempt with a result of 'successful';
- 'Multiple connections' refers to more than one successful contact attempt;
- 'Average time between connections' is calculated as the difference between the latest and earliest successful contact dates in days.

sql:
SELECT AVG(successful_contacts) AS overall_avg_successful_contacts
FROM (
  SELECT customer_id, SUM(CASE WHEN contact_result = 'successful' THEN 1 ELSE 0 END) AS successful_contacts
  FROM contacts
  GROUP BY customer_id
) AS customer_successful_contacts;
